import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";

// ─── Gambar dari template Word (embedded base64) ──────────────────────────
const INV_BG = "data:image/png;base64,";
const INV_LOGO_WM = "data:image/png;base64,";
const INV_STAMP = "data:image/png;base64,";
const INV_ICON_LOC = "data:image/png;base64,";
const INV_ICON_WEB = "data:image/png;base64,";
const INV_ICON_TEL = "data:image/png;base64,";
const INV_ICON_IG = "data:image/png;base64,";
const INV_ICON_MAIL = "data:image/png;base64,";

// ─── Helpers ─────────────────────────────────────────────────────────────
function terbilang(angka: number): string {
  const satuan = ["", "Satu", "Dua", "Tiga", "Empat", "Lima", "Enam", "Tujuh", "Delapan", "Sembilan",
    "Sepuluh", "Sebelas", "Dua Belas", "Tiga Belas", "Empat Belas", "Lima Belas",
    "Enam Belas", "Tujuh Belas", "Delapan Belas", "Sembilan Belas"];
  const puluhan = ["", "", "Dua Puluh", "Tiga Puluh", "Empat Puluh", "Lima Puluh",
    "Enam Puluh", "Tujuh Puluh", "Delapan Puluh", "Sembilan Puluh"];
  if (angka < 20) return satuan[angka];
  if (angka < 100) return puluhan[Math.floor(angka / 10)] + (angka % 10 ? " " + satuan[angka % 10] : "");
  if (angka < 200) return "Seratus" + (angka % 100 ? " " + terbilang(angka % 100) : "");
  if (angka < 1000) return satuan[Math.floor(angka / 100)] + " Ratus" + (angka % 100 ? " " + terbilang(angka % 100) : "");
  if (angka < 2000) return "Seribu" + (angka % 1000 ? " " + terbilang(angka % 1000) : "");
  if (angka < 1000000) return terbilang(Math.floor(angka / 1000)) + " Ribu" + (angka % 1000 ? " " + terbilang(angka % 1000) : "");
  if (angka < 1000000000) return terbilang(Math.floor(angka / 1000000)) + " Juta" + (angka % 1000000 ? " " + terbilang(angka % 1000000) : "");
  return terbilang(Math.floor(angka / 1000000000)) + " Miliar" + (angka % 1000000000 ? " " + terbilang(angka % 1000000000) : "");
}

function formatRupiah(angka: number): string {
  return "Rp" + new Intl.NumberFormat("id-ID").format(angka);
}

function formatTanggal(date: Date): string {
  return date.toLocaleDateString("id-ID", { weekday: "long", day: "numeric", month: "long", year: "numeric" });
}

function loadImg(src: string): Promise<HTMLImageElement> {
  return new Promise((res, rej) => {
    const img = new Image();
    img.onload = () => res(img);
    img.onerror = rej;
    img.src = src;
  });
}

// Render image ke canvas dengan opacity tertentu, return PNG dataURL
function imgWithOpacity(img: HTMLImageElement, opacity: number): string {
  const canvas = document.createElement("canvas");
  canvas.width = img.naturalWidth || img.width;
  canvas.height = img.naturalHeight || img.height;
  const ctx = canvas.getContext("2d")!;
  ctx.globalAlpha = opacity;
  ctx.drawImage(img, 0, 0);
  return canvas.toDataURL("image/png");
}

// ─── Export utama ─────────────────────────────────────────────────────────
export const generateRegistrationPdf = async (data: {
  santri: any;
  transaksi: any;
  program: any;
  dufah?: any;
  isRenew?: boolean;
  noKwitansi?: string;
  qrUrl?: string; // URL untuk QR code footer, misal link ke invoice online
}) => {
  return new Promise<void>(async (resolve, reject) => {
    try {
      // ── Load semua gambar ──────────────────────────────────────────
      const [bgImg, logoWmImg, stampImg, iconLocImg, iconWebImg, iconTelImg, iconIgImg, iconMailImg, qrImg] =
        await Promise.all([
          loadImg(INV_BG),
          loadImg(INV_LOGO_WM),
          loadImg(INV_STAMP),
          loadImg(INV_ICON_LOC),
          loadImg(INV_ICON_WEB),
          loadImg(INV_ICON_TEL),
          loadImg(INV_ICON_IG),
          loadImg(INV_ICON_MAIL),
          loadImg("/images/invoice-qr.png"),
        ]);

      // Background dengan opacity 15% agar tidak menutupi konten
      const bgFaded = imgWithOpacity(bgImg, 0.15);

      // ── Setup doc ──────────────────────────────────────────────────
      const doc = new jsPDF({ unit: "mm", format: "a4" });
      const pageW = 210;
      const pageH = 297;
      const marginL = 18;
      const marginR = 18;
      const contentW = pageW - marginL - marginR;
      const gold: [number, number, number] = [212, 175, 55];
      const dark: [number, number, number] = [20, 20, 20];
      const brown: [number, number, number] = [60, 40, 10];

      const noKwitansi = data.transaksi?.noKwitansi ?? data.noKwitansi ?? `KWM-${Date.now()}`;
      const tanggalInvoice = formatTanggal(new Date());
      const totalTagihan = data.transaksi.totalTagihan as number;
      const diskon = (data.transaksi.diskon ?? 0) as number;
      const subtotal = totalTagihan + diskon;
      const terbilangText = terbilang(totalTagihan) + " Rupiah";

      // ── LAYER 0: Background ornamen (opacity 40%) ──────────────────
      doc.addImage(bgFaded, "PNG", 0, 0, pageW, pageH);

      // ── Logo Markaz kuning di header kiri ──────────────────────────
      doc.addImage(logoWmImg, "PNG", marginL, 8, 20, 20);

      // ── HEADER ────────────────────────────────────────────────────
      const textX = marginL + 23;
      doc.setFont("helvetica", "bold");
      doc.setFontSize(15);
      doc.setTextColor(...dark);
      doc.text("MARKAZ ARABIYAH", textX, 16);
      doc.setFont("helvetica", "normal");
      doc.setFontSize(8);
      doc.setTextColor(...brown);
      doc.text("Berbasis Multiple Intelligences", textX, 21);
      doc.text("Jl. Cempaka No.32, Pare, Kediri, Jawa Timur", textX, 26);

      // INVOICE title (kanan)
      doc.setFont("helvetica", "bold");
      doc.setFontSize(24);
      doc.setTextColor(...gold);
      doc.setFont("helvetica", "normal");
      doc.setFontSize(9);
      doc.setTextColor(...dark);

      // Garis emas header
      doc.setDrawColor(...gold);
      doc.setLineWidth(0.8);
      doc.line(marginL, 31, pageW - marginR, 31);

      // ── NO KWITANSI & TANGGAL ──────────────────────────────────────
      let y = 39;
      doc.setFontSize(9);
      doc.setFont("helvetica", "bold");
      doc.setTextColor(...dark);
      doc.text("No Kwitansi", marginL, y);
      doc.text(":", marginL + 30, y);
      doc.setFont("helvetica", "normal");
      doc.text(noKwitansi, marginL + 33, y);
      doc.setFont("helvetica", "bold");
      doc.text("Tanggal", pageW / 2 + 8, y);
      doc.text(":", pageW / 2 + 24, y);
      doc.setFont("helvetica", "normal");
      doc.text(tanggalInvoice, pageW / 2 + 27, y);

      // ── DATA TAGIHAN ──────────────────────────────────────────────
      y += 8;
      const tl = data.santri.tanggalLahir
        ? new Date(data.santri.tanggalLahir).toLocaleDateString("id-ID")
        : "-";

      const labelX = marginL;
      const sepX = marginL + 38;
      const valX = marginL + 41;

      const rows: [string, string][] = [
        ["Tagihan untuk", data.santri.nama ?? "-"],
        ["NIK / NIS", data.santri.nik ?? data.santri.nis ?? "-"],
        ["Jenis Kelamin", data.santri.gender === "BANIN" ? "Laki-laki" : "Perempuan"],
        ["TTL", `${data.santri.tempatLahir ?? "-"}, ${tl}`],
        ["No WhatsApp Wali", data.santri.noWaOrtu ?? "-"],
        ["Alamat", data.santri.detailAlamat ?? "-"],
      ];

      // Block background data
      doc.setFillColor(253, 250, 240);
      doc.setDrawColor(...gold);
      doc.setLineWidth(0.3);
      const blockH = rows.length * 6 + 6;
      doc.rect(marginL - 2, y - 5, contentW + 4, blockH, "FD");

      doc.setFontSize(9);
      for (const [label, val] of rows) {
        doc.setFont("helvetica", "bold");
        doc.setTextColor(...brown);
        doc.text(label, labelX, y);
        doc.setTextColor(...dark);
        doc.text(":", sepX, y);
        doc.setFont("helvetica", "normal");
        const wrapped = doc.splitTextToSize(val, contentW - 45);
        doc.text(wrapped, valX, y);
        y += 5.5 * (wrapped.length > 1 ? wrapped.length * 0.85 : 1);
      }

      // ── SEJUMLAH ──────────────────────────────────────────────────
      y += 3;
      doc.setFillColor(245, 235, 200);
      doc.setDrawColor(...gold);
      doc.setLineWidth(0.4);
      doc.rect(marginL - 2, y - 4, contentW + 4, 14, "FD");
      doc.setFont("helvetica", "bold");
      doc.setFontSize(9);
      doc.setTextColor(...brown);
      doc.text("Sejumlah", labelX, y + 1);
      doc.setTextColor(...dark);
      doc.text(":", sepX, y + 1);
      doc.setFont("helvetica", "bold");
      doc.setFontSize(11);
      doc.setTextColor(...gold);
      doc.text(formatRupiah(totalTagihan), valX, y + 1);
      doc.setFont("helvetica", "italic");
      doc.setFontSize(8);
      doc.setTextColor(...brown);
      doc.text(`(${terbilangText})`, valX, y + 7);
      doc.setTextColor(...dark);
      y += 19;

      // ── TABEL DETAIL ──────────────────────────────────────────────
      const tableBody: any[][] = [[
        { content: data.program.nama + `\n(${data.program.durasiBulan} Duf'ah)\nMulai: ${data.dufah?.nama ?? '-'}`, styles: { fontStyle: "bold" } },
        { content: formatRupiah(subtotal), styles: { halign: "right" } },
        { content: String(data.transaksi.jumlahUnit ?? 1), styles: { halign: "center" } },
        { content: formatRupiah(subtotal * (data.transaksi.jumlahUnit ?? 1)), styles: { halign: "right" } },
      ]];

      if (diskon > 0) {
        tableBody.push([
          { content: `Potongan ${data.transaksi.persenDiskon ?? ""}%`, styles: { textColor: [180, 0, 0] } },
          { content: `- ${formatRupiah(diskon)}`, styles: { halign: "right", textColor: [180, 0, 0] } },
          { content: String(data.transaksi.jumlahUnit ?? 1), styles: { halign: "center", textColor: [180, 0, 0] } },
          { content: `- ${formatRupiah(diskon * (data.transaksi.jumlahUnit ?? 1))}`, styles: { halign: "right", textColor: [180, 0, 0] } },
        ]);
      }

      autoTable(doc, {
        startY: y,
        theme: "grid",
        tableWidth: contentW,
        margin: { left: marginL, right: marginR },
        headStyles: { fillColor: gold, textColor: [255, 255, 255], fontStyle: "bold", fontSize: 9, halign: "center" },
        bodyStyles: { fontSize: 9, textColor: dark },
        alternateRowStyles: { fillColor: [252, 248, 238] },
        columnStyles: {
          0: { cellWidth: contentW * 0.45 },
          1: { cellWidth: contentW * 0.22, halign: "right" },
          2: { cellWidth: contentW * 0.10, halign: "center" },
          3: { cellWidth: contentW * 0.23, halign: "right" },
        },
        head: [["Detail Tagihan", "Harga", "Unit", "Total"]],
        body: tableBody,
        foot: [[
          { content: "TOTAL", colSpan: 3, styles: { fontStyle: "bold", halign: "right", fillColor: [245, 235, 200] as [number, number, number] } },
          { content: formatRupiah(totalTagihan), styles: { fontStyle: "bold", halign: "right", textColor: gold, fillColor: [245, 235, 200] as [number, number, number] } },
        ]],
        footStyles: { fontSize: 9 },
      });

      y = (doc as any).lastAutoTable.finalY + 5;

      // ── KODE UNIK ─────────────────────────────────────────────────
      if (data.transaksi.kodeUnik) {
        doc.setFontSize(8);
        doc.setFont("helvetica", "italic");
        doc.setTextColor(120, 100, 50);
        doc.text(
          `*Pastikan transfer tepat hingga 3 digit terakhir (${data.transaksi.kodeUnik}) untuk verifikasi otomatis`,
          marginL, y
        );
        doc.setTextColor(...dark);
        y += 6;
      }

      // ── PERNYATAAN ────────────────────────────────────────────────
      doc.setDrawColor(...gold);
      doc.setFillColor(253, 250, 240);
      doc.setLineWidth(0.4);
      const stmtH = 13;
      doc.rect(marginL, y, contentW, stmtH, "FD");
      doc.setFont("helvetica", "bold");
      doc.setFontSize(8.5);
      doc.setTextColor(...dark);
      const stmt = "Saya setuju untuk tidak merefund atau mengalihkan pembayaran ke orang lain dengan keadaan sadar.";
      doc.text(doc.splitTextToSize(stmt, contentW - 6), marginL + 3, y + 4.5);
      y += stmtH + 6;

      // ── REKENING + TANDA TANGAN ───────────────────────────────────
      // Rekening (kiri)
      doc.setFontSize(9);
      doc.setFont("helvetica", "normal");
      doc.setTextColor(...dark);
      doc.text("Rekening pembayaran", marginL, y);
      y += 5;

      doc.setFont("helvetica", "bold");
      doc.setFontSize(10);
      doc.setTextColor(50, 100, 180); // Warna biru untuk Bank BRI
      doc.text("Bank BRI", marginL, y + 1);

      doc.setTextColor(...dark);
      doc.setFontSize(9);
      doc.setFont("helvetica", "bold");
      doc.text("No. Rek : 055501001108569", marginL, y + 6);
      doc.text("A/N Markaz Arabiyah", marginL, y + 11);

      // Stempel dan Tanda tangan (kanan)
      const sigX = pageW - marginR - 65;
      doc.setFontSize(9);
      doc.setFont("helvetica", "normal");
      doc.setTextColor(...dark);
      doc.text(`Pare, ${tanggalInvoice}`, sigX + 32, y - 5, { align: "center" });

      // Stempel ditengah tanda tangan
      doc.addImage(stampImg, "PNG", sigX + 5, y - 2, 26, 26);

      doc.setFont("helvetica", "bold");
      doc.setFontSize(9.5);
      doc.text("Kharismaning Ulfa Awwalina", sigX + 32, y + 20, { align: "center" });

      doc.setFont("helvetica", "normal");
      doc.setFontSize(8.5);
      doc.text("(Manager Keuangan", sigX + 32, y + 24, { align: "center" });
      doc.text("Markaz Arabiyah)", sigX + 32, y + 28, { align: "center" });

      // ══════════════════════════════════════════════════════════════
      // FOOTER — Layout sesuai foto 2:
      // [Ikon + kontak kiri] | [QR code tengah] | [Alamat kanan]
      // ══════════════════════════════════════════════════════════════
      const footerTop = pageH - 28;  // footer mulai 28mm dari bawah

      // Garis emas atas footer
      doc.setDrawColor(...gold);
      doc.setLineWidth(0.6);
      doc.line(marginL, footerTop, pageW - marginR, footerTop);

      // ── Kolom KIRI: 4 baris kontak ───────────────────────────────
      const iconSz = 3.5;
      const fy0 = footerTop + 5;   // baseline baris pertama
      const lineGap = 5.5;
      const iconOffY = -2.8;            // offset ikon relatif ke baseline teks
      doc.setFontSize(7.5);
      doc.setFont("helvetica", "normal");
      doc.setTextColor(50, 40, 10);

      const contactItems = [
        { icon: iconTelImg, text: "081 212 887788" },
        { icon: iconIgImg, text: "@markazarabiyah" },
        { icon: iconMailImg, text: "markazarabiyah@gmail.com" },
        { icon: iconWebImg, text: "www.markazarabiyah.com" },
      ];
      let cfx = marginL;
      contactItems.forEach((item, i) => {
        const cy = fy0 + i * lineGap;
        doc.addImage(item.icon, "PNG", cfx, cy + iconOffY, iconSz, iconSz);
        doc.text(item.text, cfx + iconSz + 1.5, cy);
      });

      // ── Kolom TENGAH: QR code ─────────────────────────────────────
      const qrSize = 22;
      const qrX = pageW / 2 - 25;
      const qrY = footerTop + 3;
      doc.addImage(qrImg, "PNG", qrX, qrY, qrSize, qrSize);

      // ── Kolom KANAN: Alamat ───────────────────────────────────────
      const addrX = pageW / 2 + 5;
      const addrLines = [
        "Jalan Cempaka 32, Tegalsari,",
        "Tulungrejo, Pare, Kediri,",
        "Jawa Timur, Indonesia",
      ];
      doc.setFontSize(7.5);
      doc.setFont("helvetica", "normal");
      doc.setTextColor(50, 40, 10);

      // Icon Location
      doc.addImage(iconLocImg, "PNG", addrX, fy0 + iconOffY + 2.5, iconSz, iconSz);

      addrLines.forEach((line, i) => {
        doc.text(line, addrX + iconSz + 1.5, fy0 + i * 5.2);
      });

      // ── SAVE ─────────────────────────────────────────────────────
      doc.save(`Invoice_${data.isRenew ? "DaftarUlang" : "Pendaftaran"}_${(data.santri.nama ?? "santri").replace(/\s+/g, "_")}.pdf`);
      resolve();

    } catch (err) {
      console.error(err);
      reject(err);
    }
  });
};

export const generateRombonganInvoicePdf = async (rombongan: any) => {
  return new Promise<void>(async (resolve, reject) => {
    try {
      const [bgImg, logoWmImg, stampImg, iconLocImg, iconWebImg, iconTelImg, iconIgImg, iconMailImg, qrImg] =
        await Promise.all([
          loadImg(INV_BG),
          loadImg(INV_LOGO_WM),
          loadImg(INV_STAMP),
          loadImg(INV_ICON_LOC),
          loadImg(INV_ICON_WEB),
          loadImg(INV_ICON_TEL),
          loadImg(INV_ICON_IG),
          loadImg(INV_ICON_MAIL),
          loadImg("/images/invoice-qr.png"),
        ]);



      const bgFaded = imgWithOpacity(bgImg, 0.15);

      const doc = new jsPDF({ unit: "mm", format: "a4" });
      const pageW = 210;
      const pageH = 297;
      const marginL = 18;
      const marginR = 18;
      const contentW = pageW - marginL - marginR;
      const gold: [number, number, number] = [212, 175, 55];
      const dark: [number, number, number] = [20, 20, 20];
      const brown: [number, number, number] = [60, 40, 10];

      const noKwitansi = rombongan.transaksi?.[0]?.noKwitansi ? `BATCH-${rombongan.transaksi[0].noKwitansi.split('-')[1] ?? Date.now()}` : `KWM-BATCH-${Date.now()}`;
      const tanggalInvoice = formatTanggal(new Date());
      const totalTagihan = rombongan.totalTagihan;
      const terbilangText = terbilang(totalTagihan) + " Rupiah";

      doc.addImage(bgFaded, "PNG", 0, 0, pageW, pageH);
      doc.addImage(logoWmImg, "PNG", marginL, 8, 20, 20);

      const textX = marginL + 23;
      doc.setFont("helvetica", "bold");
      doc.setFontSize(15);
      doc.setTextColor(...dark);
      doc.text("MARKAZ ARABIYAH", textX, 16);
      doc.setFont("helvetica", "normal");
      doc.setFontSize(8);
      doc.setTextColor(...brown);
      doc.text("Berbasis Multiple Intelligences", textX, 21);
      doc.text("Jl. Cempaka No.32, Pare, Kediri, Jawa Timur", textX, 26);

      doc.setDrawColor(...gold);
      doc.setLineWidth(0.8);
      doc.line(marginL, 31, pageW - marginR, 31);

      let y = 39;
      doc.setFontSize(9);
      doc.setFont("helvetica", "bold");
      doc.setTextColor(...dark);
      doc.text("No Kwitansi", marginL, y);
      doc.text(":", marginL + 30, y);
      doc.setFont("helvetica", "normal");
      doc.text(noKwitansi, marginL + 33, y);
      doc.setFont("helvetica", "bold");
      doc.text("Tanggal", pageW / 2 + 8, y);
      doc.text(":", pageW / 2 + 24, y);
      doc.setFont("helvetica", "normal");
      doc.text(tanggalInvoice, pageW / 2 + 27, y);

      y += 8;
      const labelX = marginL;
      const sepX = marginL + 38;
      const valX = marginL + 41;

      const rows: [string, string][] = [
        ["Tagihan untuk", "Rombongan / Lembaga"],
        ["Nama Rombongan", rombongan.nama ?? "-"],
        ["Jumlah Santri", `${rombongan.transaksi?.length ?? 0} Orang`],
      ];

      doc.setFillColor(253, 250, 240);
      doc.setDrawColor(...gold);
      doc.setLineWidth(0.3);
      const blockH = rows.length * 6 + 6;
      doc.rect(marginL - 2, y - 5, contentW + 4, blockH, "FD");

      doc.setFontSize(9);
      for (const [label, val] of rows) {
        doc.setFont("helvetica", "bold");
        doc.setTextColor(...brown);
        doc.text(label, labelX, y);
        doc.setTextColor(...dark);
        doc.text(":", sepX, y);
        doc.setFont("helvetica", "normal");
        const wrapped = doc.splitTextToSize(val, contentW - 45);
        doc.text(wrapped, valX, y);
        y += 5.5 * (wrapped.length > 1 ? wrapped.length * 0.85 : 1);
      }

      y += 3;
      doc.setFillColor(245, 235, 200);
      doc.setDrawColor(...gold);
      doc.setLineWidth(0.4);
      doc.rect(marginL - 2, y - 4, contentW + 4, 14, "FD");
      doc.setFont("helvetica", "bold");
      doc.setFontSize(9);
      doc.setTextColor(...brown);
      doc.text("Sejumlah", labelX, y + 1);
      doc.setTextColor(...dark);
      doc.text(":", sepX, y + 1);
      doc.setFont("helvetica", "bold");
      doc.setFontSize(11);
      doc.setTextColor(...gold);
      doc.text(formatRupiah(totalTagihan), valX, y + 1);
      doc.setFont("helvetica", "italic");
      doc.setFontSize(8);
      doc.setTextColor(...brown);
      doc.text(`(${terbilangText})`, valX, y + 7);
      doc.setTextColor(...dark);
      y += 19;

      const tableBody: any[][] = [];
      let totalSub = 0;
      let totalDiskon = 0;

      rombongan.transaksi?.forEach((t: any, i: number) => {
        const harga = t.nominalProgram || (t.program ? t.program.harga : t.totalTagihan);
        const diskonSatuan = Math.max(0, harga - t.totalTagihan);
        totalSub += harga;
        totalDiskon += diskonSatuan;
        tableBody.push([
          { content: `${i + 1}. ${t.santri.nama}\n   Program: ${t.program.nama}`, styles: { halign: "left" } },
          { content: formatRupiah(harga), styles: { halign: "right" } },
          { content: diskonSatuan > 0 ? `-${formatRupiah(diskonSatuan)}` : "-", styles: { halign: "right", textColor: diskonSatuan > 0 ? [180, 0, 0] : dark } },
          { content: formatRupiah(t.totalTagihan), styles: { halign: "right" } },
        ]);
      });

      autoTable(doc, {
        startY: y,
        theme: "grid",
        tableWidth: contentW,
        margin: { left: marginL, right: marginR },
        headStyles: { fillColor: gold, textColor: [255, 255, 255], fontStyle: "bold", fontSize: 9, halign: "center" },
        bodyStyles: { fontSize: 9, textColor: dark },
        alternateRowStyles: { fillColor: [252, 248, 238] },
        columnStyles: {
          0: { cellWidth: contentW * 0.45 },
          1: { cellWidth: contentW * 0.20, halign: "right" },
          2: { cellWidth: contentW * 0.15, halign: "right" },
          3: { cellWidth: contentW * 0.20, halign: "right" },
        },
        head: [["Daftar Santri & Program", "Biaya", "Diskon", "Total"]],
        body: tableBody,
        foot: [[
          { content: "TOTAL", styles: { fontStyle: "bold", halign: "right", fillColor: [245, 235, 200] as [number, number, number] } },
          { content: formatRupiah(totalSub), styles: { fontStyle: "bold", halign: "right", fillColor: [245, 235, 200] as [number, number, number] } },
          { content: totalDiskon > 0 ? `-${formatRupiah(totalDiskon)}` : "-", styles: { fontStyle: "bold", halign: "right", textColor: [180, 0, 0], fillColor: [245, 235, 200] as [number, number, number] } },
          { content: formatRupiah(totalTagihan), styles: { fontStyle: "bold", halign: "right", textColor: gold, fillColor: [245, 235, 200] as [number, number, number] } },
        ]],
      });

      // TTD
      let finalY = (doc as any).lastAutoTable.finalY + 15;
      if (finalY > pageH - 50) {
        doc.addPage();
        finalY = 20;
        doc.addImage(bgFaded, "PNG", 0, 0, pageW, pageH);
      }

      doc.setFont("helvetica", "normal");
      doc.setFontSize(9);
      doc.setTextColor(...dark);
      doc.text(`Pare, ${tanggalInvoice}`, pageW - marginR - 35, finalY, { align: "center" });
      doc.text("Markaz Arabiyah", pageW - marginR - 35, finalY + 5, { align: "center" });

      const stampW = 40;
      const stampH = 40;
      doc.addImage(stampImg, "PNG", pageW - marginR - 55, finalY + 2, stampW, stampH);
      doc.setFont("helvetica", "bold");
      doc.text("Kharismaning Ulfa Awwalina", pageW - marginR - 35, finalY + 32, { align: "center" });

      // Footer
      const footerTop = pageH - 35;
      doc.setDrawColor(...gold);
      doc.setLineWidth(0.5);
      doc.line(marginL, footerTop, pageW - marginR, footerTop);

      const fy0 = footerTop + 6;
      doc.setFontSize(7.5);
      doc.setFont("helvetica", "bold");
      doc.setTextColor(...brown);
      doc.text("Lembaga Markaz Arabiyah Pare", marginL, fy0);
      doc.setFont("helvetica", "normal");
      doc.setTextColor(50, 40, 10);

      const iconSz = 4.5;
      const iconOffY = -3.5;
      const cfx = marginL;
      const contactInfo = [
        { icon: iconWebImg, text: "www.markazarabiyah.id" },
        { icon: iconIgImg, text: "@markazarabiyah" },
        { icon: iconMailImg, text: "markazarabiyah@gmail.com" },
        { icon: iconTelImg, text: "0812-4241-1181" },
      ];

      contactInfo.forEach((item, i) => {
        const cy = fy0 + 5.5 + i * 5;
        doc.addImage(item.icon, "PNG", cfx, cy + iconOffY, iconSz, iconSz);
        doc.text(item.text, cfx + iconSz + 1.5, cy);
      });

      const qrSize = 22;
      const qrX = pageW / 2 - 25;
      const qrY = footerTop + 3;
      doc.addImage(qrImg, "PNG", qrX, qrY, qrSize, qrSize);

      const addrX = pageW / 2 + 5;
      const addrLines = [
        "Jalan Cempaka 32, Tegalsari,",
        "Tulungrejo, Pare, Kediri,",
        "Jawa Timur, Indonesia",
      ];
      doc.addImage(iconLocImg, "PNG", addrX, fy0 + iconOffY + 2.5, iconSz, iconSz);
      addrLines.forEach((line, i) => {
        doc.text(line, addrX + iconSz + 1.5, fy0 + i * 5.2);
      });

      doc.save(`Invoice_Rombongan_${(rombongan.nama ?? "rombongan").replace(/\s+/g, "_")}.pdf`);
      resolve();
    } catch (err) {
      console.error(err);
      reject(err);
    }
  });
};